/**
 * PluginApiClient provides typed methods for common Paca API calls.
 * Plugin route calls are prefixed with `/plugins/{pluginId}/`.
 * Use the `projectId` property to include project context in paths when needed:
 *   `pluginGet(id, \`/projects/${api.projectId}/my-resource\`)`
 */
export declare class PluginApiClient {
    private readonly baseUrl;
    readonly projectId: string;
    private readonly _fetch;
    constructor(opts: PluginApiClientOptions);
    /** List tasks for the current project with optional filters. */
    listTasks(filters?: TaskFilters): Promise<TaskSummary[]>;
    /** Get a single task by ID. */
    getTask(taskId: string): Promise<Task>;
    /** Get the current project summary. */
    getProject(): Promise<ProjectSummary>;
    /** List members of the current project. */
    listMembers(): Promise<ProjectMember[]>;
    /**
     * Call a GET route registered by this plugin.
     * The URL is built as `{baseUrl}/plugins/{pluginId}{path}`.
     * For project-scoped routes, include the project prefix in `path`:
     *   `pluginGet(id, \`/projects/${api.projectId}/resource\`)`
     */
    pluginGet<T>(pluginId: string, path: string): Promise<T>;
    /**
     * Call a POST route registered by this plugin.
     */
    pluginPost<T>(pluginId: string, path: string, body: unknown): Promise<T>;
    /**
     * Call a PATCH route registered by this plugin.
     */
    pluginPatch<T>(pluginId: string, path: string, body: unknown): Promise<T>;
    /**
     * Call a DELETE route registered by this plugin.
     */
    pluginDelete(pluginId: string, path: string): Promise<void>;
    private _pluginUrl;
    private _get;
    private _request;
}

export declare interface PluginApiClientOptions {
    /** Base URL of the paca API, e.g. "https://app.paca.dev/api/v1". */
    baseUrl: string;
    /** Current project ID (injected by the host). */
    projectId: string;
    /** Axios-compatible function for authenticated fetches (injected by host). */
    fetch: (url: string, init?: RequestInit) => Promise<Response>;
}

export declare interface PluginContextValue {
    /** HTTP client scoped to the current project and authenticated session. */
    api: PluginApiClient;
    /** Host UI utilities: toast, confirm, navigate. */
    ui: PluginUI;
    /** Metadata about the plugin itself. */
    meta: PluginMeta;
}

/** Metadata injected into every plugin component via PluginMeta prop. */
