/**
 * Wrap your plugin component tree with `<PluginProvider>` to make the SDK
 * context available to all descendant components.
 *
 * The host application does this automatically for registered extension point
 * components; plugin authors only need to add a Provider when writing tests or
 * standalone stories.
 */
export declare function PluginProvider({ api, ui, meta, children, }: PluginProviderProps): JSX.Element;

export declare interface PluginProviderProps {
    api: PluginApiClient;
    ui?: PluginUI;
    meta: PluginMeta;
    children: ReactNode;
}

/**
 * Re-uses the host's QueryClient if one is already present in the tree,
 * otherwise creates an isolated client.  Plugins should mount this at the
 * root of their component tree.
 */
export declare function PluginQueryClientProvider({ children, queryClient, }: {
    children: ReactNode;
    /** Pass the host QueryClient instance here if available. */
    queryClient?: QueryClient;
}): JSX.Element;

/**
 * PluginUI exposes host-level UI interactions to plugin components.
 * An instance is injected by the host via PluginContext.
 */
export declare interface PluginUI {
    /**
     * Display a toast notification.
     * @example sdk.ui.toast({ title: "Saved", variant: "success" });
     */
    toast(opts: ToastOptions): void;
    /**
     * Open a confirmation dialog and return true when the user confirms.
     * Returns false on cancel or dismissal.
     * @example const ok = await sdk.ui.confirm({ title: "Delete item?", variant: "destructive" });
     */
    confirm(opts: ConfirmOptions): Promise<boolean>;
    /**
     * Navigate to a path within the host application using the host router.
     * Paths are relative to the app root, e.g. "/projects/abc/tasks/123".
     */
    navigate(path: string): void;
}

