/**
 * Access the plugin SDK from any component inside a `<PluginProvider>`.
 *
 * @example
 * ```tsx
 * function MySection() {
 *   const { api, ui, meta } = usePlugin();
 *   ...
 * }
 * ```
 */
export declare function usePlugin(): PluginContextValue;

/**
 * Like `useQuery` but automatically namespaces the query key under
 * `["plugin", pluginId, ...queryKey]` to avoid cache collisions.
 *
 * @example
 * ```tsx
 * const { api, meta } = usePlugin();
 * const { data } = usePluginQuery(meta.pluginId, ["items", taskId], () =>
 *   api.pluginGet(meta.pluginId, `/tasks/${taskId}/items`)
 * );
 * ```
 */
export declare function usePluginQuery<TData = unknown, TError = Error>(pluginId: string, queryKey: unknown[], queryFn: () => Promise<TData>, options?: Omit<UseQueryOptions<TData, TError, TData, unknown[]>, "queryKey" | "queryFn">): UseQueryResult<TData, TError>;

/** Access the QueryClient from context (for manual invalidation). */
export declare function usePluginQueryClient(): QueryClient;

